.demo-word-fade { color: var(--sm-content-primary, #171717); }
.demo-word-fade .txt { font: 700 28px/1.45 "Pretendard", system-ui, sans-serif; text-align: center; max-width: 720px; margin: 0; }
.demo-word-fade .w { display: inline-block; opacity: 0; transform: translateY(10px); transition: opacity 600ms cubic-bezier(0.2,0,0,1), transform 600ms cubic-bezier(0.2,0,0,1); }
.demo-word-fade .w.on { opacity: 1; transform: translateY(0); }

blocks.js:
(function(){
  var box = document.querySelector(".demo-word-fade");
  if (!box) return;
  var txt = box.querySelector(".txt");
  var orig = txt.dataset.orig || txt.textContent;
  txt.dataset.orig = orig;
  function play(){
    var words = orig.split(" ");
    txt.innerHTML = words.map(function(w){ return "<span class=\"w\">" + w + "</span>"; }).join(" ");
    var spans = txt.querySelectorAll(".w");
    spans.forEach(function(s, i){ s.style.transitionDelay = (i * 70) + "ms"; });
    setTimeout(function(){
      spans.forEach(function(s){ s.classList.add("on"); });
    }, 30);
  }
  play();
  box.querySelector(".pattern-replay").addEventListener("click", play);
})();

