blocks.js:
(function(){
  var box = document.querySelector(".demo-line-slide");
  if (!box) return;
  var lns = box.querySelectorAll(".ln");
  lns.forEach(function(ln){
    if (!ln.dataset.wrapped) {
      var t = ln.textContent;
      ln.dataset.text = t;
      ln.innerHTML = "<span>" + t + "</span>";
      ln.dataset.wrapped = "1";
    }
  });
  function play(){
    lns.forEach(function(ln){ ln.classList.remove("on"); });
    setTimeout(function(){
      lns.forEach(function(ln, i){
        setTimeout(function(){ ln.classList.add("on"); }, i * 140);
      });
    }, 30);
  }
  play();
  box.querySelector(".pattern-replay").addEventListener("click", play);
})();

