blocks.css:
.demo-scrub-color { gap: 28px; }
.demo-scrub-color .txt { font: 700 26px/1.5 "Pretendard", system-ui; color: #d4d4d4; text-align: center; max-width: 680px; margin: 0; }
.demo-scrub-color .w { display: inline-block; transition: color 220ms; }
.demo-scrub-color .w.on { color: var(--sm-content-primary, #171717); }
.demo-scrub-color .scrub-track { width: 280px; height: 4px; background: #e5e5e5; border-radius: 2px; overflow: hidden; }
.demo-scrub-color .scrub-fill { width: 0; height: 100%; background: #171717; }

blocks.js:
(function(){
  var box = document.querySelector(".demo-scrub-color");
  if (!box) return;
  var txt = box.querySelector(".txt");
  var fill = box.querySelector(".scrub-fill");
  var orig = txt.dataset.orig || txt.textContent;
  txt.dataset.orig = orig;
  var timer = null;
  function play(){
    txt.innerHTML = orig.split(" ").map(function(w){ return "<span class=\"w\">" + w + "</span>"; }).join(" ");
    var spans = txt.querySelectorAll(".w");
    fill.style.width = "0%";
    if (timer) clearInterval(timer);
    var dur = 2400, start = Date.now();
    timer = setInterval(function(){
      var p = Math.min(1, (Date.now() - start) / dur);
      fill.style.width = (p * 100) + "%";
      var idx = Math.floor(p * spans.length);
      spans.forEach(function(s, i){ if (i < idx) s.classList.add("on"); });
      if (p >= 1) { spans.forEach(function(s){ s.classList.add("on"); }); clearInterval(timer); }
    }, 33);
  }
  play();
  box.querySelector(".pattern-replay").addEventListener("click", play);
})();

